package com.bankingapp.transactions;

import android.content.Context;
import android.util.Log;
import java.math.BigDecimal;
import java.security.SecureRandom;

public class TransactionProcessor {

    private static final String TAG = "TransactionProcessor";
    private BigDecimal accountBalance;

    public TransactionProcessor(BigDecimal initialBalance) {
        this.accountBalance = initialBalance;
    }

    // Simple transaction processing method
    public boolean processTransaction(BigDecimal amount, String type) {
        if (amount == null || amount.compareTo(BigDecimal.ZERO) <= 0) {
            Log.e(TAG, "Invalid transaction amount");
            return false;
        }

        synchronized (this) {
            if ("deposit".equalsIgnoreCase(type)) {
                accountBalance = accountBalance.add(amount);
                Log.d(TAG, "Deposited: " + amount + ", New Balance: " + accountBalance);
            } else if ("withdraw".equalsIgnoreCase(type)) {
                if (accountBalance.compareTo(amount) < 0) {
                    Log.e(TAG, "Insufficient funds");
                    return false;
                }
                accountBalance = accountBalance.subtract(amount);
                Log.d(TAG, "Withdrew: " + amount + ", New Balance: " + accountBalance);
            } else {
                Log.e(TAG, "Unknown transaction type");
                return false;
            }
        }
        return true;
    }

    // Display current account balance
    public String getAccountBalance() {
        return accountBalance.toPlainString();
    }

    // Simple security enhancement using SecureRandom for initial release
    public void secureSessionStart(Context context) {
        SecureRandom random = new SecureRandom();
        byte[] sessionKey = new byte[16];
        random.nextBytes(sessionKey);
        Log.d(TAG, "Session Key generated: " + bytesToHex(sessionKey));
        // Implement additional security measures based on user feedback
    }

    private String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }
}